package com.example.hybridapp

import android.Manifest
import android.app.Activity
import android.content.Context
import android.content.Intent
import android.content.pm.PackageManager
import android.net.Uri
import android.os.Bundle
import android.provider.MediaStore
import android.webkit.*
import android.widget.Toast
import androidx.activity.result.contract.ActivityResultContracts
import androidx.appcompat.app.AppCompatActivity
import androidx.core.content.ContextCompat
import androidx.core.content.FileProvider
import org.json.JSONObject
import java.io.File
import java.text.SimpleDateFormat
import java.util.*

class MainActivity : AppCompatActivity() {
    private lateinit var webView: WebView
    private lateinit var bridgeInterface: SecureWebBridge
    private var photoUri: Uri? = null

    private val allowedOrigins = setOf(
        "https://yourdomain.com",
        "https://www.yourdomain.com"
    )

    private val cameraLauncher = registerForActivityResult(
        ActivityResultContracts.TakePicture()
    ) { success ->
        if (success) {
            photoUri?.let { uri ->
                bridgeInterface.notifyCameraResult(true, uri.toString())
            }
        } else {
            bridgeInterface.notifyCameraResult(false, null)
        }
    }

    private val cameraPermissionLauncher = registerForActivityResult(
        ActivityResultContracts.RequestPermission()
    ) { granted ->
        if (granted) {
            launchCamera()
        } else {
            bridgeInterface.notifyCameraResult(false, null)
        }
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        webView = findViewById(R.id.webView)
        bridgeInterface = SecureWebBridge(this, allowedOrigins)

        setupWebView()
        loadInitialUrl()
    }

    private fun setupWebView() {
        webView.settings.apply {
            javaScriptEnabled = true
            domStorageEnabled = true
            databaseEnabled = false
            allowFileAccess = false
            allowContentAccess = false
            allowFileAccessFromFileURLs = false
            allowUniversalAccessFromFileURLs = false
            mixedContentMode = WebSettings.MIXED_CONTENT_NEVER_ALLOW
            setSupportMultipleWindows(false)
            javaScriptCanOpenWindowsAutomatically = false
        }

        webView.addJavascriptInterface(bridgeInterface, "NativeBridge")

        webView.webViewClient = SecureWebViewClient(allowedOrigins)
        webView.webChromeClient = object : WebChromeClient() {
            override fun onConsoleMessage(consoleMessage: ConsoleMessage?): Boolean {
                return true
            }
        }

        CookieManager.getInstance().apply {
            setAcceptCookie(true)
            setAcceptThirdPartyCookies(webView, false)
        }
    }

    private fun loadInitialUrl() {
        val initialUrl = "https://yourdomain.com"
        if (isAllowedOrigin(initialUrl)) {
            webView.loadUrl(initialUrl)
        }
    }

    private fun isAllowedOrigin(url: String): Boolean {
        return try {
            val uri = Uri.parse(url)
            val origin = "${uri.scheme}://${uri.host}"
            allowedOrigins.contains(origin)
        } catch (e: Exception) {
            false
        }
    }

    fun requestCameraAccess() {
        when {
            ContextCompat.checkSelfPermission(
                this,
                Manifest.permission.CAMERA
            ) == PackageManager.PERMISSION_GRANTED -> {
                launchCamera()
            }
            else -> {
                cameraPermissionLauncher.launch(Manifest.permission.CAMERA)
            }
        }
    }

    private fun launchCamera() {
        val photoFile = createImageFile()
        photoUri = FileProvider.getUriForFile(
            this,
            "${packageName}.fileprovider",
            photoFile
        )
        cameraLauncher.launch(photoUri)
    }

    private fun createImageFile(): File {
        val timeStamp = SimpleDateFormat("yyyyMMdd_HHmmss", Locale.US).format(Date())
        val storageDir = getExternalFilesDir(null)
        return File.createTempFile("IMG_${timeStamp}_", ".jpg", storageDir)
    }

    override fun onBackPressed() {
        if (webView.canGoBack()) {
            webView.goBack()
        } else {
            super.onBackPressed()
        }
    }

    class SecureWebViewClient(private val allowedOrigins: Set<String>) : WebViewClient() {
        override fun shouldOverrideUrlLoading(
            view: WebView?,
            request: WebResourceRequest?
        ): Boolean {
            val url = request?.url?.toString() ?: return true
            
            if (!isAllowedOrigin(url)) {
                return true
            }

            return false
        }

        override fun onReceivedSslError(
            view: WebView?,
            handler: SslErrorHandler?,
            error: SslError?
        ) {
            handler?.cancel()
        }

        private fun isAllowedOrigin(url: String): Boolean {
            return try {
                val uri = Uri.parse(url)
                val origin = "${uri.scheme}://${uri.host}"
                allowedOrigins.contains(origin)
            } catch (e: Exception) {
                false
            }
        }
    }

    class SecureWebBridge(
        private val activity: MainActivity,
        private val allowedOrigins: Set<String>
    ) {
        private var cameraCallback: String? = null

        @JavascriptInterface
        fun requestCamera(callbackId: String) {
            if (!validateCallbackId(callbackId)) return

            cameraCallback = callbackId
            activity.runOnUiThread {
                activity.requestCameraAccess()
            }
        }

        @JavascriptInterface
        fun saveToStorage(key: String, value: String): Boolean {
            if (!validateStorageKey(key) || !validateStorageValue(value)) {
                return false
            }

            return try {
                val prefs = activity.getSharedPreferences("AppStorage", Context.MODE_PRIVATE)
                prefs.edit().putString(sanitizeKey(key), value).apply()
                true
            } catch (e: Exception) {
                false
            }
        }

        @JavascriptInterface
        fun getFromStorage(key: String): String? {
            if (!validateStorageKey(key)) {
                return null
            }

            return try {
                val prefs = activity.getSharedPreferences("AppStorage", Context.MODE_PRIVATE)
                prefs.getString(sanitizeKey(key), null)
            } catch (e: Exception) {
                null
            }
        }

        @JavascriptInterface
        fun removeFromStorage(key: String): Boolean {
            if (!validateStorageKey(key)) {
                return false
            }

            return try {
                val prefs = activity.getSharedPreferences("AppStorage", Context.MODE_PRIVATE)
                prefs.edit().remove(sanitizeKey(key)).apply()
                true
            } catch (e: Exception) {
                false
            }
        }

        @JavascriptInterface
        fun requestPushPermission(callbackId: String) {
            if (!validateCallbackId(callbackId)) return

            activity.runOnUiThread {
                val result = JSONObject().apply {
                    put("callbackId", callbackId)
                    put("granted", true)
                }
                executeCallback("window.NativeBridge._onPushPermission($result)")
            }
        }

        fun notifyCameraResult(success: Boolean, imageUri: String?) {
            cameraCallback?.let { callbackId ->
                val result = JSONObject().apply {
                    put("callbackId", callbackId)
                    put("success", success)
                    if (success && imageUri != null) {
                        put("imageUri", imageUri)
                    }
                }
                executeCallback("window.NativeBridge._onCameraResult($result)")
                cameraCallback = null
            }
        }

        private fun executeCallback(script: String) {
            activity.runOnUiThread {
                activity.webView.evaluateJavascript(script, null)
            }
        }

        private fun validateCallbackId(callbackId: String): Boolean {
            return callbackId.matches(Regex("^[a-zA-Z0-9_-]{1,64}$"))
        }

        private fun validateStorageKey(key: String): Boolean {
            return key.isNotEmpty() && 
                   key.length <= 256 && 
                   key.matches(Regex("^[a-zA-Z0-9._-]+$"))
        }

        private fun validateStorageValue(value: String): Boolean {
            return value.length <= 1048576
        }

        private fun sanitizeKey(key: String): String {
            return key.replace(Regex("[^a-zA-Z0-9._-]"), "")
        }
    }
}